def split_words(txt):
    '''
    Given a string of words, return a list of words split on semicolons, if no semicolons exist in the text you
    should split on hyphens. If no hyphens exist you should return the count of lower-case letters with odd order in the 
    alphabet, ord('a') = 26, ord('b') = 25, ... ord('z') = 1.
    Examples
    split_words("Hello world!") ➞ ["Hello world!"]
    split_words("Hello;world!") ➞ ["Hello","world!"]
    split_words("abcdeF") == 3
    '''
    if ';' in txt:
        return txt.split(';')
    elif '-' in txt:
        return txt.split('-')
    else:
        return sum(1 for char in txt if char.islower() and (ord(char) - ord('a') + 1) % 2 == 1)
